import{c as a,bn as e,aU as r,aX as d,u as l,$ as h}from"./chunks/framework.BZ6QiwKG.js";const m=JSON.parse('{"title":"伽岚","description":"","frontmatter":{"order":6},"headers":[],"relativePath":"地图/幽冥血海/伽岚.md","filePath":"地图/幽冥血海/伽岚.md","lastUpdated":0}'),n={name:"地图/幽冥血海/伽岚.md"};function i(s,t,o,b,c,x){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="伽岚" tabindex="-1">伽岚 <a class="header-anchor" href="#伽岚" aria-label="Permalink to “伽岚”">​</a></h1><h2 id="小怪掉落" tabindex="-1">小怪掉落 <a class="header-anchor" href="#小怪掉落" aria-label="Permalink to “小怪掉落”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">木类材料</th><th style="text-align:center;">矿类材料</th><th style="text-align:center;">布类材料</th></tr></thead><tbody><tr><td style="text-align:center;">桃木枝</td><td style="text-align:center;">丹霞土</td><td style="text-align:center;">赤焰葛</td></tr></tbody></table><h2 id="桃止山" tabindex="-1">桃止山 <a class="header-anchor" href="#桃止山" aria-label="Permalink to “桃止山”">​</a></h2><h3 id="五奇冥鬼" tabindex="-1">五奇冥鬼 <a class="header-anchor" href="#五奇冥鬼" aria-label="Permalink to “五奇冥鬼”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>场景中将会对应出现各属性场景机关，在机关内停留3秒可以消除对应属性debuff：<br>金毒-火场景，木毒-金场景，水毒-土场景，火毒-水场景，土毒-木场景</td></tr><tr><td>五奇冥吸：五鬼化做魂魄向敌人方向移动，之后持续吸收范围内的生气，将对范围内的敌人造成伤害并将敌人吸引到身前（通用技能）</td></tr><tr><td>金镰勾魂：金鬼挥舞镰刀对敌人造成四段攻击伤害，命中将会给敌人附上金毒效果；金毒：降低攻击力</td></tr><tr><td>木影缠魂：木鬼高举棍子朝前方劈下，同时向前方蔓延出藤蔓对碰到的敌人造成伤害，命中将会给敌人附上木毒效果；木毒：降低闪避</td></tr><tr><td>水缚魂鞭：水鬼挥舞长鞭环绕自身，片刻之后将会挥舞长鞭攻击敌人，命中将会给敌人附上水毒效果；水毒：降低回蓝</td></tr><tr><td>火劫撩斩：火鬼瞬移至玩家左方提刀上撩，之后瞬移至玩家右方持刀下劈，命中将会给敌人附上火毒效果；火毒：降低暴击</td></tr><tr><td>土轮旋裂：土鬼提起石锤朝敌人方向旋斩，并跃起将石锤砸下，命中将会给敌人附上土毒效果；土毒：提升受到的伤害</td></tr><tr><td>土裂千岩：土鬼使用石锤左右重砸地面，将落下碎石对敌人造成伤害</td></tr><tr><td>五奇摄魂：五鬼能够将一定范围内的敌人摄到身前（噩梦模式下通用技能）</td></tr><tr><td>五奇冥斩：玩家身上积攒到五种属性的效果后，将会触发斩杀技，对范围内的敌人斩杀（仅限噩梦模式）</td></tr></tbody></table><p>掉落道具：伽岚防具制作书</p><h2 id="幽都鬼城" tabindex="-1">幽都鬼城 <a class="header-anchor" href="#幽都鬼城" aria-label="Permalink to “幽都鬼城”">​</a></h2><h3 id="幽冥鬼母" tabindex="-1">幽冥鬼母 <a class="header-anchor" href="#幽冥鬼母" aria-label="Permalink to “幽冥鬼母”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>剜心龙爪：鬼母挥爪攻击前方3次</td></tr><tr><td>擒魂鬼爪：鬼母伸出鬼爪抓取前方敌人，将前方的敌人拉至身前</td></tr><tr><td>幽冥爪刃：鬼母瞬移至敌人上方，向下挥爪（被命中的敌人短时间内无法跳跃），落地时同时向前方劈出爪刃</td></tr><tr><td>鬼虎扑噬：鬼母朝前方扑击，并将扑中的敌人撕裂开，并使其眩晕且进入撕裂状态（撕裂：移动将会持续扣血）</td></tr><tr><td>虎跃落袭：鬼母跃向边上柱子，停驻在柱子，从柱子弹射向玩家位置砸落</td></tr><tr><td>噬魂鬼影：鬼母飘向空中召出十只鬼子虚影并在体表生成护盾，鬼子虚影将在鬼母施法后向上进行爪击，同时鬼母出现在敌人上方向下砸落（击破鬼母护盾，鬼母将会随机吞食一边的五只鬼子虚影回复自身）</td></tr></tbody></table><p>掉落道具：伽岚武器制作书（第一心法）</p><h2 id="幽都鬼城隐藏" tabindex="-1">幽都鬼城隐藏 <a class="header-anchor" href="#幽都鬼城隐藏" aria-label="Permalink to “幽都鬼城隐藏”">​</a></h2><p>使用普通攻击点亮两盏灯，然后从地面出现的缺口向下</p><p>走到最左侧使用普通攻击破坏墙壁，向下走到底，进入<strong>隐藏关卡</strong></p><img src="'+l+'" alt="幽都鬼城隐藏" style="zoom:50%;"><h3 id="幽冥鬼子" tabindex="-1">幽冥鬼子 <a class="header-anchor" href="#幽冥鬼子" aria-label="Permalink to “幽冥鬼子”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>幽冥瘴域：每10秒在自身下方生成毒圈（使敌人中毒、禁止跳跃），持续一段时间</td></tr><tr><td>鬼爪连击：挥爪攻击前方2次</td></tr><tr><td>虎啸狂蚀：受到惊吓后跳，朝前低吼，恐吓敌人并使其混乱</td></tr><tr><td>冥虎疾冲：脑袋朝前顶，撞飞碰到敌人</td></tr><tr><td>鬼虎裂爪：高高跃起，而后向下劈爪攻击敌人</td></tr><tr><td>幽虎影爪：瞬移至敌人上空，而后垂直下落攻击敌人</td></tr><tr><td>毒噬分影：化为毒雾分影消失，而后依次随机出现毒雾，毒雾出现一段时间后，从中伸出爪子攻击敌人后；攻击真身毒雾后，幽冥鬼子才会再次出现</td></tr><tr><td>鬼影双生：在其中一个毒圈处召唤兄弟魂魄；幽冥鬼子濒临死亡时，若场上存在魂魄，幽冥鬼子会吸收兄弟魂魄回复自身血量</td></tr><tr><td>龙鳞护甲：生成半透明龙鳞护盾，受到攻击反弹伤害</td></tr></tbody></table><p>掉落道具：伽岚武器制作书（第二心法）</p><h2 id="万世冥阁" tabindex="-1">万世冥阁 <a class="header-anchor" href="#万世冥阁" aria-label="Permalink to “万世冥阁”">​</a></h2><h3 id="鬼帝郁垒" tabindex="-1">鬼帝郁垒 <a class="header-anchor" href="#鬼帝郁垒" aria-label="Permalink to “鬼帝郁垒”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>剑断黄泉：挥动长剑，挑出2道剑气向外移动</td></tr><tr><td>阴罗劫火：将剑插入地面对敌人造成晕眩，随后将剑拔出，拔出时地面会带出紫色火焰</td></tr><tr><td>审无常：在场景右侧生成3个小阵眼，从阵眼射出桃木剑（被桃木剑打到的敌人攻击降低，持续一段时间）</td></tr><tr><td>查万物：在场景中央生成一把巨大的桃木剑阵（一段时间内未打破阵眼，巨剑分散成多把剑，对全屏敌人造成高额伤害</td></tr><tr><td>万鬼枷锁：放出苇索，在空中交织成「万鬼枷锁」结界</td></tr><tr><td>命门逆克：单手举起，召唤命门，受到攻击会回复生命</td></tr><tr><td>被动：当其中一个鬼帝死亡后，若10秒内另一个鬼帝未死亡，复活并回复血量</td></tr></tbody></table><h3 id="鬼帝神荼" tabindex="-1">鬼帝神荼 <a class="header-anchor" href="#鬼帝神荼" aria-label="Permalink to “鬼帝神荼”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>贯骨锁魂：使用戟斜刺向前方</td></tr><tr><td>厄难困仙：挥舞手中的苇索，甩向敌人。如果命中，则会拘束敌人（敌人被拘束时，无法使用技能），离开一定范围苇索断开。若一段时间内敌人未逃离，神荼会拉回苇索并使其眩晕</td></tr><tr><td>束无常：在场景左侧生成3个小阵眼，从阵眼射出战戟（被战戟打到的敌人会获得禁跳效果，持续一段时间）</td></tr><tr><td>困万物：在场景中间召唤一个拘魂阵，对全屏玩家造成牵引，处于法阵内会受到持续伤害</td></tr><tr><td>万鬼枷锁：放出苇索，在空中交织成「万鬼枷锁」结界</td></tr><tr><td>命门逆克：单手举起，召唤命门，受到攻击会回复生命</td></tr><tr><td>被动：当其中一个鬼帝死亡后，若10秒内另一个鬼帝未死亡，复活并回复血量</td></tr></tbody></table><p>掉落道具：<a href="/zmxy4-helpPages/饰品/常见主线饰品.html#伽岚清心铃">伽岚清心铃制作书</a></p><h2 id="法宝" tabindex="-1">法宝 <a class="header-anchor" href="#法宝" aria-label="Permalink to “法宝”">​</a></h2><h3 id="伽岚桃虎符" tabindex="-1">伽岚桃虎符 <a class="header-anchor" href="#伽岚桃虎符" aria-label="Permalink to “伽岚桃虎符”">​</a></h3><img src="'+h+'" alt="伽岚桃虎符" style="zoom:50%;"><table tabindex="0"><thead><tr><th style="text-align:center;">被动</th><th style="text-align:center;">属性</th></tr></thead><tbody><tr><td style="text-align:center;">回血</td><td style="text-align:center;">21~29</td></tr><tr><td style="text-align:center;">回魔</td><td style="text-align:center;">12~17</td></tr><tr><td style="text-align:center;">吸血</td><td style="text-align:center;">16~22</td></tr><tr><td style="text-align:center;">反伤</td><td style="text-align:center;">16~22</td></tr></tbody></table>',28)])])}const p=a(n,[["render",i]]);export{m as __pageData,p as default};
